const source = $('Set - Source Config').first().json;
const data = $json.result || {};

const ids = Array.isArray(data.uids) ? data.uids : [];

const candidates = ids.map((uid, idx) => {
  const item = data[uid] || {};

  const title = item.title || '';
  const pubdate = item.pubdate || '';
  const sourceName = item.fulljournalname || item.source || '';
  const articleIds = Array.isArray(item.articleids) ? item.articleids : [];

  let doi = '';
  for (const a of articleIds) {
    if (String(a.idtype || '').toLowerCase() === 'doi') {
      doi = a.value || '';
      break;
    }
  }

  return {
    source_id: source.source_id,
    corpus: source.corpus,
    content_subtype: source.content_subtype || null,
    source_kind: 'html_page',
    candidate_index: idx,
    url: `https://pubmed.ncbi.nlm.nih.gov/${uid}/`,
    pdf_url: '',
    title,
    description: sourceName,
    published_at: pubdate,
    updated_at: '',
    topic: source.topic || '',
    region: '',
    domain: '',
    doi,
    pmid: uid
  };
}).filter(x => x.title && x.pmid);

return [{
  json: {
    source_id: source.source_id,
    corpus: source.corpus,
    content_subtype: source.content_subtype || null,
    front_page_size: source.front_page_size,
    warm_depth: source.warm_depth,
    next_backfill_offset: source.next_backfill_offset,
    candidates
  }
}];

const source = $('Set - Source Config').first().json;
const html = $json.data || $json.body || $json || '';

function clean(text = '') {
  return String(text)
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

function makeAbsoluteUrl(href, baseUrl) {
  if (!href) return '';
  if (href.startsWith('http://') || href.startsWith('https://')) return href;
  if (href.startsWith('//')) return `https:${href}`;
  if (href.startsWith('/')) return `${baseUrl}${href}`;
  return `${baseUrl}/${href}`;
}

const matches = [...String(html).matchAll(/<a[^>]+href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi)];

const seen = new Set();
const candidates = [];

for (const m of matches) {
  const href = makeAbsoluteUrl(m[1], source.base_url || '');
  const title = clean(m[2]);

  if (!href) continue;
  if (!title || title.length < 10) continue;

  const looksRelevant =
    /disease-outbreak-news|\/item\/|\.pdf/i.test(href);

  if (!looksRelevant) continue;

  const key = `${href}|||${title}`.toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);

  const isPdf = /\.pdf(\?|#|$)/i.test(href);

  candidates.push({
    source_id: source.source_id,
    corpus: source.corpus,
    content_subtype: source.content_subtype || null,
    source_kind: isPdf ? 'pdf_url' : 'html_page',
    candidate_index: candidates.length,
    url: isPdf ? '' : href,
    pdf_url: isPdf ? href : '',
    title,
    description: '',
    published_at: '',
    updated_at: '',
    topic: source.topic || '',
    region: source.region || '',
    domain: source.domain || '',
    doi: '',
    pmid: ''
  });

  if (candidates.length >= (source.warm_depth || 21)) break;
}

return [{
  json: {
    source_id: source.source_id,
    corpus: source.corpus,
    content_subtype: source.content_subtype || null,
    front_page_size: source.front_page_size,
    warm_depth: source.warm_depth,
    next_backfill_offset: source.next_backfill_offset,
    candidates
  }
}];

const payload = $json;
const candidates = payload.candidates || [];
const frontSize = payload.front_page_size || 7;
const nextOffset = payload.next_backfill_offset || frontSize;

const frontCandidates = candidates.slice(0, frontSize);
const backfillCandidates = candidates.slice(nextOffset, nextOffset + (payload.warm_depth || 21));

return [{
  json: {
    source_id: payload.source_id,
    corpus: payload.corpus,
    content_subtype: payload.content_subtype,
    front_page_size: frontSize,
    next_backfill_offset: nextOffset,
    frontCandidates,
    backfillCandidates
  }
}];

const candidate = $("Switch - Decide Front Ingest Transport").item.json;
const response = $json || {};
const validActions = new Set(['created', 'updated', 'skipped', 'failed']);

function asObject(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function toText(value) {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string') return value.trim();
  try {
    return JSON.stringify(value);
  } catch (error) {
    return String(value);
  }
}

function resolveAction(payload) {
  const topLevel = String(payload.action || '').toLowerCase();
  if (validActions.has(topLevel)) return topLevel;

  const documents = Array.isArray(payload.documents) ? payload.documents : [];
  for (const document of documents) {
    const documentAction = String(document?.action || '').toLowerCase();
    if (validActions.has(documentAction)) return documentAction;
  }

  const created = Number(payload.created || 0);
  const updated = Number(payload.updated || 0);
  const skipped = Number(payload.skipped || 0);
  const failed = Number(payload.failed || 0);

  if (updated > 0) return 'updated';
  if (created > 0) return 'created';
  if (skipped > 0) return 'skipped';
  if (failed > 0 || String(payload.status || '').toLowerCase() === 'failed') return 'failed';
  return '';
}

const body = asObject(response.body);
const payload = Object.keys(body).length ? body : asObject(response);
const primaryDocument = (Array.isArray(payload.documents) ? payload.documents : []).find((item) => item && typeof item === 'object') || {};
const statusCode = Number(response.statusCode || payload.statusCode || 0);
let action = resolveAction(payload);

if (response.error || statusCode >= 400) {
  action = 'failed';
}
if (!validActions.has(action)) {
  action = 'failed';
}

const message =
  toText(response.error?.description) ||
  toText(response.error?.message) ||
  toText(payload.detail) ||
  toText(payload.message) ||
  (action === 'failed' ? 'Backend ingest failed' : `backend ingest: ${action}`);

return [{
  json: {
    ...candidate,
    action,
    document_id: payload.document_id || primaryDocument.document_id || '',
    version_id: payload.version_id || primaryDocument.version_id || '',
    ingest_job_id: payload.ingest_job_id || '',
    message,
  }
}];

const rows = $input.all().map(i => i.json);

let created = 0;
let updated = 0;
let skipped = 0;
let failed = 0;

for (const r of rows) {
  if (r.action === 'created') created++;
  else if (r.action === 'updated') updated++;
  else if (r.action === 'skipped') skipped++;
  else failed++;
}

const frontPageSize = $('Set - Source Config').first().json.front_page_size || 7;
const remainingSlots = Math.max(0, frontPageSize - (created + updated));

return [{
  json: {
    created,
    updated,
    skipped,
    failed,
    remainingSlots
  }
}];

const scan = $('Code - Build Scan Plan').first().json;
const remain = $('Code - Count Front Results').first().json.remainingSlots || 0;

// scan nhiều hơn số còn thiếu để bù cho trường hợp skipped
const picked = (scan.backfillCandidates || []).slice(0, Math.max(remain * 2, remain));

return picked.map(it => ({
  json: {
    ...it,
    phase: 'backfill'
  }
}));

const candidate = $("Switch - Decide Backfill Ingest Transport").item.json;
const response = $json || {};
const validActions = new Set(['created', 'updated', 'skipped', 'failed']);

function asObject(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function toText(value) {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string') return value.trim();
  try {
    return JSON.stringify(value);
  } catch (error) {
    return String(value);
  }
}

function resolveAction(payload) {
  const topLevel = String(payload.action || '').toLowerCase();
  if (validActions.has(topLevel)) return topLevel;

  const documents = Array.isArray(payload.documents) ? payload.documents : [];
  for (const document of documents) {
    const documentAction = String(document?.action || '').toLowerCase();
    if (validActions.has(documentAction)) return documentAction;
  }

  const created = Number(payload.created || 0);
  const updated = Number(payload.updated || 0);
  const skipped = Number(payload.skipped || 0);
  const failed = Number(payload.failed || 0);

  if (updated > 0) return 'updated';
  if (created > 0) return 'created';
  if (skipped > 0) return 'skipped';
  if (failed > 0 || String(payload.status || '').toLowerCase() === 'failed') return 'failed';
  return '';
}

const body = asObject(response.body);
const payload = Object.keys(body).length ? body : asObject(response);
const primaryDocument = (Array.isArray(payload.documents) ? payload.documents : []).find((item) => item && typeof item === 'object') || {};
const statusCode = Number(response.statusCode || payload.statusCode || 0);
let action = resolveAction(payload);

if (response.error || statusCode >= 400) {
  action = 'failed';
}
if (!validActions.has(action)) {
  action = 'failed';
}

const message =
  toText(response.error?.description) ||
  toText(response.error?.message) ||
  toText(payload.detail) ||
  toText(payload.message) ||
  (action === 'failed' ? 'Backend ingest failed' : `backend ingest: ${action}`);

return [{
  json: {
    ...candidate,
    action,
    document_id: payload.document_id || primaryDocument.document_id || '',
    version_id: payload.version_id || primaryDocument.version_id || '',
    ingest_job_id: payload.ingest_job_id || '',
    message,
  }
}];

const front = $('Code - Count Front Results').first().json;
const source = $('Set - Source Config').first().json;

return [{
  json: {
    source_id: source.source_id,
    corpus: source.corpus,
    content_subtype: source.content_subtype || null,
    front_created: front.created,
    front_updated: front.updated,
    front_skipped: front.skipped,
    backfill_created: 0,
    backfill_updated: 0,
    backfill_skipped: 0,
    failed: front.failed || 0,
    next_backfill_offset_suggested: source.next_backfill_offset || 7,
    message: (front.failed || 0) > 0
      ? `Front scan completed without backfill, ${front.failed} item(s) failed`
      : 'Front scan completed without backfill'
  }
}];

const front = $('Code - Count Front Results').first().json;
const backfillRows = $input.all().map(i => i.json);

let backfillCreated = 0;
let backfillUpdated = 0;
let backfillSkipped = 0;
let backfillFailed = 0;

for (const r of backfillRows) {
  if (r.action === 'created') backfillCreated++;
  else if (r.action === 'updated') backfillUpdated++;
  else if (r.action === 'skipped') backfillSkipped++;
  else backfillFailed++;
}

const source = $('Set - Source Config').first().json;
const scannedBackfill = backfillRows.length;
const newOffset = (source.next_backfill_offset || 7) + scannedBackfill;

return [{
  json: {
    source_id: source.source_id,
    corpus: source.corpus,
    content_subtype: source.content_subtype || null,
    front_created: front.created,
    front_updated: front.updated,
    front_skipped: front.skipped,
    backfill_created: backfillCreated,
    backfill_updated: backfillUpdated,
    backfill_skipped: backfillSkipped,
    failed: (front.failed || 0) + backfillFailed,
    next_backfill_offset_suggested: newOffset,
    message: backfillFailed > 0
      ? `Front scan + backfill completed with ${backfillFailed} backfill failure(s)`
      : 'Front scan + backfill completed'
  }
}];

const data = $json;

return [{
  json: {
    source_id: data.source_id,
    total_front: (data.frontCandidates || []).length,
    total_backfill: (data.backfillCandidates || []).length,
    front_titles: (data.frontCandidates || []).slice(0, 5).map(x => x.title),
    backfill_titles: (data.backfillCandidates || []).slice(0, 5).map(x => x.title),
  }
}];

return [{
  json: {
    source_id: $json.source_id,
    message: 'Parser chưa lấy đủ candidate hợp lệ. Không nên update source này.',
    candidate_count: ($json.candidates || []).length
  }
}];

const source = $('Set - Source Config').first().json;
const result = $json.esearchresult || {};

return [{
  json: {
    source_id: source.source_id,
    corpus: source.corpus,
    content_subtype: source.content_subtype || null,
    front_page_size: source.front_page_size,
    warm_depth: source.warm_depth,
    next_backfill_offset: source.next_backfill_offset,
    topic: source.topic || '',
    query: source.query,
    count: Number(result.count || 0),
    query_key: result.querykey,
    webenv: result.webenv
  }
}];

const payload = $json;
const candidates = payload.candidates || [];

// từ khóa nên giữ
const includeKeywords = [
  'respiratory',
  'pneumonia',
  'influenza',
  'acute respiratory distress syndrome',
  'ards',
  'dyspnea',
  'copd',
  'lung',
  'pulmonary',
  'thoracic',
  'covid',
  'tuberculosis',
  'tb',
  'non-small cell lung cancer',
  'nsclc',
  'pleural',
  'airway',
  'bronch',
  'trachea'
];

// từ khóa nên loại
const excludeKeywords = [
  'pericarditis',
  'appendicitis',
  'uterine',
  'endometrial',
  'gastrointestinal',
  'obesity'
];

function containsAny(text, words) {
  const t = String(text || '').toLowerCase();
  return words.some(w => t.includes(w));
}

const filtered = candidates.filter(item => {
  // chỉ lọc theo title + journal/source, KHÔNG dùng item.topic
  const haystack = [
    item.title || '',
    item.description || ''
  ].join(' ').toLowerCase();

  const include = containsAny(haystack, includeKeywords);
  const exclude = containsAny(haystack, excludeKeywords);

  return include && !exclude;
}).map((item, idx) => ({
  ...item,
  candidate_index: idx
}));

return [{
  json: {
    ...payload,
    candidates: filtered
  }
}];
